args.sparql:
SELECT (COUNT(?country) + 1 AS ?rank)
WHERE {
  wd:Q150 wdt:P1082 ?pop_pak.
  ?country wdt:P31 wd:Q6256 ;
          wdt:P1082 ?pop_country.
  FILTER (?pop_country > ?pop_pak)
}

